app.get('/userinfo', async (req, res) => {
  const auth = req.headers.authorization || '';
  if (!auth.startsWith('Bearer ')) return res.status(401).json({ error: 'invalid_token' });

  const token = auth.slice(7);
  const raw = await redis.get(`access:${token}`);
  if (!raw) return res.status(401).json({ error: 'invalid_token' });

  const data = JSON.parse(raw);
  if (data.exp < nowSeconds()) return res.status(401).json({ error: 'invalid_token' });

  res.json({ sub: data.userId, scope: data.scope });
});

app.post('/login', async (req, res) => {
  const { username } = req.body;
  if (!username) return res.status(400).json({ error: 'invalid_request' });
  res.json(await issueTokens({ userId: username, scope: 'default' }));
});

